    private lateinit var prefs: SharedPreferences

    private var fileChooserCallback: ValueCallback<Array<Uri>>? = null
    private lateinit var fileChooserLauncher: ActivityResultLauncher<Intent>
    private lateinit var requestPermissionLauncher: ActivityResultLauncher<Array<String>>

    private val pendingPermissionRequests = ConcurrentHashMap<String, PendingPermissionRequest>()
    private data class PendingPermissionRequest(
        val permissions: Array<String>,
        val onResultJsCallback: String?
    )

    companion object {
        const val EXTRA_URL = "extra_url"

        private const val DEFAULT_URL = "https://example.com"
        private const val PREFS_NAME = "hybrid_webview_prefs"

        private const val REQ_CODE_CAMERA_PERMISSION_FALLBACK = 4512

        fun intent(context: Context, url: String = DEFAULT_URL): Intent =
            Intent(context, HybridWebViewActivity::class.java).putExtra(EXTRA_URL, url)
    }

    @SuppressLint("SetJavaScriptEnabled")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        webView = WebView(this)
        setContentView(webView)

        fileChooserLauncher = registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            val callback = fileChooserCallback
            fileChooserCallback = null
            if (callback == null) return@registerForActivityResult

            val uris = if (result.resultCode == Activity.RESULT_OK) {
                val data = result.data
                val clip = data?.clipData
                when {
                    clip != null && clip.itemCount > 0 -> Array(clip.itemCount) { i -> clip.getItemAt(i).uri }
                    data?.data != null -> arrayOf(data.data!!)
                    else -> emptyArray()
                }
            } else {
                emptyArray()
            }
            callback.onReceiveValue(uris)
        }

        requestPermissionLauncher = registerForActivityResult(ActivityResultContracts.RequestMultiplePermissions()) { results ->
            val entry = pendingPermissionRequests.entries.firstOrNull()
            if (entry != null) {
                val token = entry.key
                val pending = entry.value
                pendingPermissionRequests.remove(token)
                val granted = pending.permissions.all { perm -> results[perm] == true }
                if (!pending.onResultJsCallback.isNullOrBlank()) {
                    postJsCallback(pending.onResultJsCallback, JSONObject().apply {
                        put("token", token)
                        put("granted", granted)
                        put("permissions", pending.permissions.joinToString(","))
                    }.toString())
                }
            }
        }

        val settings = webView.settings
        settings.javaScriptEnabled = true
        settings.domStorageEnabled = true
        settings.databaseEnabled = true
        settings.allowFileAccess = true
        settings.allowContentAccess = true
        settings.javaScriptCanOpenWindowsAutomatically = true
        settings.mediaPlaybackRequiresUserGesture = false
        settings.cacheMode = WebSettings.LOAD_DEFAULT
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            settings.safeBrowsingEnabled = true
        }
        WebView.setWebContentsDebuggingEnabled(BuildConfig.DEBUG)

        webView.addJavascriptInterface(NativeBridge(this, webView, prefs), "NativeBridge")

        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView, request: WebResourceRequest): Boolean {
                val url = request.url
                val scheme = url.scheme?.lowercase()
                return when {
                    scheme == "http" || scheme == "https" -> false
                    scheme == "mailto" || scheme == "tel" -> {
                        try { startActivity(Intent(Intent.ACTION_VIEW, url)) } catch (_: Throwable) {}
                        true
                    }
                    else -> {
                        try { startActivity(Intent(Intent.ACTION_VIEW, url)) } catch (_: Throwable) {}
                        true
                    }
                }
            }

            override fun onPageFinished(view: WebView, url: String) {
                super.onPageFinished(view, url)
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onPermissionRequest(request: PermissionRequest) {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
                    val resources = request.resources
                    val wantsVideo = resources.contains(PermissionRequest.RESOURCE_VIDEO_CAPTURE)
                    val wantsAudio = resources.contains(PermissionRequest.RESOURCE_AUDIO_CAPTURE)

                    val perms = mutableListOf<String>()
                    if (wantsVideo) perms += Manifest.permission.CAMERA
                    if (wantsAudio) perms += Manifest.permission.RECORD_AUDIO

                    if (perms.isEmpty()) {
                        request.grant(resources)
                        return
                    }

                    val allGranted = perms.all { p -> ContextCompat.checkSelfPermission(this@HybridWebViewActivity, p) == PackageManager.PERMISSION_GRANTED }
                    if (allGranted) {
                        request.grant(resources)
                        return
                    }

                    ActivityCompat.requestPermissions(this@HybridWebViewActivity, perms.toTypedArray(), REQ_CODE_CAMERA_PERMISSION_FALLBACK)
                    request.deny()
                } else {
                    super.onPermissionRequest(request)
                }
