            webView.removeJavascriptInterface("NativeBridge")
            webView.stopLoading()
            webView.webChromeClient = null
            webView.webViewClient = null
            webView.destroy()
        } catch (_: Throwable) {}
        super.onDestroy()
    }

    private fun postJsCallback(callback: String, jsonArg: String) {
        val js = if (callback.contains("(")) {
            "try { $callback; } catch(e) {}"
        } else {
            "try { $callback($jsonArg); } catch(e) {}"
        }
        runOnUiThread {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT) webView.evaluateJavascript(js, null)
            else webView.loadUrl("javascript:$js")
        }
    }

    class NativeBridge(
        private val context: Context,
        private val webView: WebView,
        private val prefs: SharedPreferences
    ) {

        private fun eval(js: String) {
            (context as? Activity)?.runOnUiThread {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT) webView.evaluateJavascript(js, null)
                else webView.loadUrl("javascript:$js")
            }
        }

        private fun safeJson(value: String?): String = JSONObject.quote(value ?: "")

        @JavascriptInterface
        fun ping(): String = "pong"

        // -------- Local Storage (native-backed) --------
        @JavascriptInterface
        fun storageSet(key: String, value: String): Boolean {
            return try {
                prefs.edit().putString(key, value).apply()
                true
            } catch (_: Throwable) {
                false
            }
        }

        @JavascriptInterface
        fun storageGet(key: String): String {
            return prefs.getString(key, "") ?: ""
        }

        @JavascriptInterface
        fun storageRemove(key: String): Boolean {
            return try {
                prefs.edit().remove(key).apply()
                true
            } catch (_: Throwable) {
                false
            }
        }

        @JavascriptInterface
        fun storageClear(): Boolean {
            return try {
                prefs.edit().clear().apply()
                true
            } catch (_: Throwable) {
                false
            }
        }

        // -------- Camera access --------
        // Preferred: use <input type="file" accept="image/*" capture> in web content.
        // This method requests CAMERA permission (if needed) and returns current permission state.
        @JavascriptInterface
        fun cameraEnsurePermission(callbackFn: String?) {
            val activity = context as? HybridWebViewActivity ?: return
            val perm = Manifest.permission.CAMERA
            val granted = ContextCompat.checkSelfPermission(activity, perm) == PackageManager.PERMISSION_GRANTED
            if (granted) {
                if (!callbackFn.isNullOrBlank()) {
                    activity.runOnUiThread {
                        activity.postJsCallback(callbackFn, JSONObject().apply {
                            put("granted", true)
                            put("permission", perm)
                        }.toString())
                    }
