                return
            }

            val token = UUID.randomUUID().toString()
            activity.pendingPermissionRequests[token] = PendingPermissionRequest(arrayOf(perm), callbackFn)
            activity.requestPermissionLauncher.launch(arrayOf(perm))
        }

        // -------- Push Notifications (FCM) --------
        @JavascriptInterface
        fun pushGetToken(callbackFn: String) {
            FirebaseMessaging.getInstance().token
                .addOnCompleteListener { task ->
                    val token = if (task.isSuccessful) task.result else null
                    val json = JSONObject().apply {
                        put("ok", task.isSuccessful)
                        put("token", token ?: JSONObject.NULL)
                    }.toString()
                    val js = "try { $callbackFn($json); } catch(e) {}"
                    eval(js)
                }
        }

        @JavascriptInterface
        fun pushSubscribeToTopic(topic: String, callbackFn: String?) {
            FirebaseMessaging.getInstance().subscribeToTopic(topic)
                .addOnCompleteListener { task ->
                    if (!callbackFn.isNullOrBlank()) {
                        val json = JSONObject().apply {
                            put("ok", task.isSuccessful)
                            put("topic", topic)
                        }.toString()
                        val js = "try { $callbackFn($json); } catch(e) {}"
                        eval(js)
                    }
                }
        }

        @JavascriptInterface
        fun pushUnsubscribeFromTopic(topic: String, callbackFn: String?) {
            FirebaseMessaging.getInstance().unsubscribeFromTopic(topic)
                .addOnCompleteListener { task ->
                    if (!callbackFn.isNullOrBlank()) {
                        val json = JSONObject().apply {
                            put("ok", task.isSuccessful)
                            put("topic", topic)
                        }.toString()
                        val js = "try { $callbackFn($json); } catch(e) {}"
                        eval(js)
                    }
                }
        }

        // -------- Utilities --------
        @JavascriptInterface
        fun openExternalUrl(url: String): Boolean {
            return try {
                val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
                intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                context.startActivity(intent)
                true
            } catch (_: Throwable) {
                false
            }
        }

        @JavascriptInterface
        fun getPlatformInfo(): String {
            return JSONObject().apply {
                put("platform", "android")
                put("sdkInt", Build.VERSION.SDK_INT)
                put("manufacturer", Build.MANUFACTURER)
                put("model", Build.MODEL)
            }.toString()
        }

        @JavascriptInterface
        fun emitEvent(eventName: String, payloadJson: String?) {
            val payload = payloadJson ?: "null"
            val js = "try { window.dispatchEvent(new CustomEvent(${safeJson(eventName)}, { detail: $payload })); } catch(e) {}"
            eval(js)
        }
    }
